static void diag_print_dec(uint32_t val)
{
    char buf[12];
    int pos = 0;
    if (val == 0) {
        diag_print("0");
        return;
    }
    while (val > 0) {
        buf[pos++] = '0' + (val % 10);
        val /= 10;
    }
    /* Reverse */
    for (int i = 0; i < pos / 2; i++) {
        char tmp = buf[i];
        buf[i] = buf[pos - 1 - i];
        buf[pos - 1 - i] = tmp;
    }
    buf[pos] = '\0';
    diag_print(buf);
}

