/* ============================================================
 * Memory region access validation
 * ============================================================ */

static bool is_address_in_allowed_region(uint32_t addr, uint32_t size, bool need_dump)
{
    uint32_t end_addr = addr + size - 1;

    /* Overflow check */
    if (end_addr < addr)
        return false;

    for (size_t i = 0; i < NUM_ALLOWED_REGIONS; i++) {
        const memory_region_t *region = &allowed_regions[i];
        if (addr >= region->start && end_addr <= region->end) {
            if (need_dump)
                return region->allow_dump;
            return region->allow_read;
        }
    }
    return false;
}

